for (const item of $input.all()) {
  const binaryKeys = Object.keys(item.binary || {});
  const attachmentKeys = binaryKeys.filter(k => k.startsWith('attachment'));

 item.json.has_attachments = Boolean(attachmentKeys.length > 0);
  item.json.attachment_count = attachmentKeys.length;
  item.json.message_id = item.json.messageId || item.json.message_id || item.json.id || item.json.uid || '';
  item.json.from_email = item.json.from?.value?.[0]?.address || item.json.from?.[0]?.address || item.json.from || '';
  item.json.subject = item.json.subject || '';
}

return $input.all();

const items = [];

for (const item of $input.all()) {
  const binaryKeys = Object.keys(item.binary || {});
  const attachmentKeys = binaryKeys.filter(k => k.startsWith('attachment'));

  for (const key of attachmentKeys) {
    items.push({
      json: {
        message_id: item.json.message_id || '',
        from_email: item.json.from_email || '',
        subject: item.json.subject || '',
        attachment_key: key,
        file_name: item.binary[key].fileName || '',
        mime_type: item.binary[key].mimeType || '',
        file_extension: (item.binary[key].fileExtension || '').toLowerCase(),
      },
      binary: {
        attachment: item.binary[key]
      }
    });
  }
}

return items;

const originalBinary = $('Code in JavaScript1').first().binary;

return [{
  json: {
    file_name: $('Code in JavaScript1').first().json.file_name,
    mime_type: $('Code in JavaScript1').first().json.mime_type,
  },
  binary: originalBinary,
  pairedItem: { item: 0 }
}];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "Full_Name": {
      "type": "string",
      "description": "Full name of the candidate"
    },
    "Email": {
      "type": "string",
      "description": "Email address of the candidate"
    },
    "Phone": {
      "type": "string",
      "description": "Phone number of the candidate"
    },
    "Position_Applied": {
      "type": "string",
      "description": "MUST be exactly one of the Position Titles from the AVAILABLE JOB OPENINGS list provided in the system message. Choose the best match."
    },
    "Location": {
      "type": "string",
      "description": "City and state/country of the candidate"
    },
    "Years_Experience": {
      "type": "string",
      "description": "Total years of professional experience as a number"
    },
    "Skills": {
      "type": "string",
      "description": "Key skills separated by commas"
    },
    "Education": {
      "type": "string",
      "description": "Highest education level or degree"
    },
    "current_position": {
      "type": "string",
      "description": "Current or most recent job title"
    },
    "AI_Score": {
      "type": "string",
      "description": "Rate the candidate from 1-100 based on overall resume quality, experience relevance, and skills"
    },
    "AI_Summary": {
      "type": "string",
      "description": "Brief 2-3 sentence professional summary of the candidate"
    }
  }
}

parameters.text:
=You are an expert HR interviewer specializing in industrial and technical positions.

Generate exactly 5 tailored interview questions for INTERNAL HR USE ONLY.

Candidate profile:
Full Name: {{ $input.item.json.fields['Candidate Name'] }}
Position Applied: {{ $input.item.json.fields['Suggested Position'] }}
Years of Experience: {{ $input.item.json.fields['Experience'] }}
Skills: {{ $input.item.json.fields['Habilities'] }}
Score: {{ $input.item.json.fields['Score'] }}
Location: {{ $input.item.json.fields['Location'] }}
AI Resume Summary: {{ $input.item.json.fields['Summary'] }}

Rules:
- Questions MUST reference the candidate's ACTUAL skills and experience
- Include 2 technical questions about their specific skills listed above
- Include 2 behavioral questions based on their years of experience
- Include 1 career goals question for the specific position
- Number each question 1-5
- Be specific: use their real skills, job title, and experience

Output ONLY the 5 numbered questions. These are for the interviewer, not the candidate.
